def gen(rng, size):
    n = max(2, min(size, 1000))
    judge = rng.randint(1, n)
    edges = set()
    for p in range(1, n + 1):
        if p != judge:
            edges.add((p, judge))
    extra = rng.randint(0, n)
    for _ in range(extra):
        a = rng.randint(1, n)
        b = rng.randint(1, n)
        if a != b and a != judge and (a, b) not in edges:
            edges.add((a, b))
    return [n, [list(e) for e in edges]]

