class Solution:
    def findJudge(self, n, trust):
        trusts = set(a for a, b in trust)
        for cand in range(1, n + 1):
            if cand in trusts:
                continue
            trusted_by = set(a for a, b in trust if b == cand)
            if len(trusted_by) == n - 1 and cand not in trusted_by:
                return cand
        return -1

